// Obtener datos de cada nodo anterior
const webhookData = $('Webhook').item.json.body || $('Webhook').item.json || {};
const question = webhookData.question || $('Webhook').item.json.question || '';
const lessonModule = webhookData.lesson_module || $('Webhook').item.json.lesson_module || '';
const userLevel = webhookData.user_level || $('Webhook').item.json.user_level || 'beginner';
const portfolioCtx = webhookData.portfolio_context || $('Webhook').item.json.portfolio_context || '';

// Procesar dólar
let dolarCtx = 'No disponible';
try {
  let dolarData;
  try {
    dolarData = $('Obtener tipos de dólar').item.json;
  } catch(e) {
    dolarData = $('Obtener tipos de dolar').item.json;
  }
  const dolarObj = dolarData?.data || dolarData || {};
  const mep = dolarObj.mep?.price || dolarObj.Bolsa?.value_sell || dolarObj.mep?.value_sell || 'N/D';
  const blue = dolarObj.blue?.price || dolarObj.Informal?.value_sell || dolarObj.blue?.value_sell || 'N/D';
  const oficial = dolarObj.oficial?.price || dolarObj.Oficial?.value_sell || 'N/D';
  dolarCtx = "MEP: $" + mep + " | Blue: $" + blue + " | Oficial: $" + oficial;
} catch(e) { dolarCtx = 'No disponible'; }

// Procesar caución BCRA
let caucionCtx = 'No disponible';
try {
  let bcraData;
  try {
    bcraData = $('Obtener tasa de caución').item.json;
  } catch(e) {
    bcraData = $('Obtener tasa de caucion').item.json;
  }
  const bcraObj = bcraData?.data || bcraData || {};
  if (bcraObj && bcraObj.tna !== undefined && bcraObj.tna !== null) {
    caucionCtx = bcraObj.tna + "% TNA";
  } else if (bcraData?.results?.length > 0) {
    const ultima = bcraData.results[bcraData.results.length - 1];
    if (ultima && ultima.valor !== undefined && ultima.valor !== null) {
      caucionCtx = ultima.valor + "% TNA (dato BCRA)";
    }
  }
} catch(e) { caucionCtx = 'No disponible'; }

// Procesar FCIs
let fciCtx = 'No disponible';
try {
  const fcis = $('Obtener FCIs').item.json;
  if (fcis?.data?.length > 0) {
    const top3 = fcis.data.slice(0, 3).map(f => 
      f.nombre + ": " + (f.rentabilidad_anual || 'N/D') + "% anual"
    ).join(' | ');
    fciCtx = top3;
  }
} catch(e) { fciCtx = 'No disponible'; }

// Procesar RAG chunks
let ragCtx = '';
try {
  const ragResults = $('Buscar en Vector Store').item.json;
  if (ragResults?.result?.length > 0) {
    ragCtx = ragResults.result
      .map(r => r.payload?.text || '')
      .filter(t => t.length > 0)
      .join('\n---\n');
  }
} catch(e) { ragCtx = ''; }

// Armar contexto final
const context = [
  "DATOS DEL MERCADO ARGENTINO (actualizados):",
  "- Tipos de cambio: " + dolarCtx,
  "- Caución bursátil: " + caucionCtx,
  "- FCIs destacados: " + fciCtx,
  "",
  portfolioCtx ? "CARTERA DEL USUARIO:\n" + portfolioCtx : "",
  "",
  ragCtx ? "CONTENIDO EDUCATIVO RELEVANTE:\n" + ragCtx : "",
  "",
  "MÓDULO QUE ESTÁ CURSANDO: " + (lessonModule && lessonModule !== 'undefined' ? lessonModule : 'Ninguno'),
  "NIVEL DEL USUARIO: " + (userLevel && userLevel !== 'undefined' ? userLevel : 'beginner')
].filter(line => line !== null).join('\n').trim();

return [{
  json: {
    question,
    context,
    lessonModule,
    userLevel,
    timestamp: new Date().toISOString()
  }
}];

