const geminiResponse = $input.item.json;
let reply = '';

try {
  reply = geminiResponse.candidates[0].content.parts[0].text;
} catch(e) {
  reply = 'Lo siento, no pude procesar tu pregunta en este momento. Intentá de nuevo en unos segundos.';
}

// Determinar fuentes usadas
const sources = [];
const ctx = $('Code - Ensamblar contexto').item.json.context;
if (ctx.includes('MEP:') && !ctx.includes('No disponible')) {
  sources.push({ name: 'Dolarito.ar', type: 'dolar' });
}
if (ctx.includes('TNA') && !ctx.includes('No disponible')) {
  sources.push({ name: 'BCRA', type: 'caucion' });
}

return [{
  json: {
    reply,
    sources,
    timestamp: new Date().toISOString(),
    model: 'gemini-2.5-flash'
  }
}];
